import React from "react";
import { useSessionContext } from "../contexts/SessionContext";
import { useState } from "react";
import { Navigate } from "react-router-dom";
import "./Login.css";

function Login() {
  const {loggedUser, setLoggedUser, setLoggedIn} = useSessionContext();
  const [id, setId] = useState('');
  const [pwd, setPwd] = useState('');

  const onSubmit = (e) => {
    e.preventDefault();
    setLoggedUser(loggedUser);
  };

  const loginBtn = (userId, userPwd) => {
    console.log(userId, userPwd);
    setLoggedUser({id: userId, pwd: userPwd});
    setLoggedIn({id: userId, pwd: userPwd});
  }

  return(
    <>
      <div className="login-box">
        <h1 className="modal-header"> Please Login! </h1>
        <div className="inputs">
          <a> ID </a>
          <input name="id" placeholder="아이디" onChange={(e) => setId(e.target.value)}/>
        </div>
        <div className="inputs">
          <a> PASSWORD </a>
          <input name="pwd" placeholder="비밀번호" onChange={(e) => setPwd(e.target.value)}/>
        </div>
        <div className="buttons">
					<button type="submit" className="submit" onClick={() => loginBtn(id, pwd)}> Login </button>
          <button type="submit" className="return-submit" onClick={<Navigate to="/" />}> Cancel </button>
        </div>
      </div>
    </>
  );
}

export default Login;